const clientId = $vars.EBAY_APP_ID;
const clientSecret = $vars.EBAY_CLIENT_SECRET;
const basicAuth = 'Basic ' + Buffer.from(clientId + ':' + clientSecret).toString('base64');
return [{ json: { basicAuth } }];

const searchResponse = $input.first().json;
const webhookData = $('Receive Research Request').first().json.body;

let listings = [];

try {
  const items = searchResponse?.itemSummaries || [];
  listings = items.slice(0, 8).map(item => ({
    title: item.title || '',
    price: item.price?.value || '0',
    currency: item.price?.currency || 'USD',
    condition: item.condition || 'Unknown',
    url: item.itemWebUrl || '',
    listedAs: `$${parseFloat(item.price?.value || '0').toFixed(2)}`
  }));
} catch (e) {
  listings = [];
}

const avgPrice = listings.length > 0
  ? listings.reduce((sum, l) => sum + parseFloat(l.price), 0) / listings.length
  : null;

return [{
  json: {
    webhookData,
    listings,
    avgListedPrice: avgPrice ? `$${avgPrice.toFixed(2)}` : null,
    searchSucceeded: listings.length > 0
  }
}];

const data = $input.first().json;
const wd = data.webhookData || {};

const listingLines = data.searchSucceeded
  ? data.listings.map((l, i) => `${i+1}. ${l.title} — Listed at ${l.listedAs} (${l.condition}) ${l.url}`).join('\n')
  : '';

const ebaySection = data.searchSucceeded
  ? `Found ${data.listings.length} current eBay listings for comparable items:\n${listingLines}\n${data.avgListedPrice ? 'Average listed price: ' + data.avgListedPrice : ''}`
  : 'No eBay listing data available — use your knowledge for estimates.';

const prompt = `You are a professional eBay reseller researcher. Analyze this auction item and provide complete research data so it can be listed on eBay profitably.

## ITEM DATA
Item Name: ${wd.itemName || ''}
Category: ${wd.category || 'Unknown'}
Description: ${wd.description || 'No description provided'}
Current Auction Bid: ${wd.currentBid || 'Unknown'}
Auction Name: ${wd.auctionName || 'Unknown'}
AI Estimate from auction site: ${wd.auctionSiteEstimate || 'Not provided'}

## CURRENT EBAY LISTINGS (active listings for price reference)
${ebaySection}

## YOUR TASK
Return ONLY a valid JSON object (no markdown, no explanation) with this exact structure:
{
  "researcherEstimate": "$X - $Y",
  "researcherDescription": "2-3 sentences: condition assessment, what makes it valuable, any caveats a buyer should know",
  "priority": "high|medium|low",
  "priorityReason": "One sentence explaining why this priority",
  "notes": "Key research notes: what to look for when photographing, any authentication concerns, best eBay category to list in",
  "referenceUrls": ["url1", "url2"],
  "confidence": "high|medium|low",
  "confidenceReason": "Why confidence is this level"
}

Priority logic:
- high: estimated profit margin > 100% over current bid, or item sells for > $200
- low: estimated profit margin < 20%, or item sells for < $30
- medium: everything else

For referenceUrls: include the eBay listing URLs from the data above if available. If none, return empty array.`;

const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 1500,
  messages: [{ role: 'user', content: prompt }]
});

return [{ json: { requestBody } }];

const claudeResponse = $input.first().json;
const originalData = $('Format eBay Results').first().json;

let research = null;
let parseError = null;

try {
  const text = claudeResponse?.content?.[0]?.text || '';
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    research = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found in Claude response');
  }
} catch (e) {
  parseError = e.message;
  research = {
    researcherEstimate: 'Could not determine — manual research needed',
    researcherDescription: 'AI analysis failed. Please research manually.',
    priority: 'medium',
    priorityReason: 'Default — could not determine automatically',
    notes: 'AI parse error: ' + parseError,
    referenceUrls: [],
    confidence: 'low',
    confidenceReason: 'Parse failure'
  };
}

return [{
  json: {
    success: !parseError,
    research,
    itemId: originalData.webhookData?.itemId,
    ebaySearchResults: originalData.listings?.length || 0,
    parseError
  }
}];
